+/// Fold select (xor (trunc (lshr/ashr X, N-1)), 1), (icmp slt X, 0), false -> false
+/// The condition is the inverted sign bit (X >= 0), and when it's true, the
+/// icmp slt (X < 0) is false. When condition is false (X < 0), the result is false.
+static Value *foldSelectInvertedSignBitWithSlt(const SelectInst &SI,
+                                               Value *CondVal, Value *TrueVal,
+                                               Value *FalseVal) {
+  if (!match(FalseVal, m_Zero()))
+    return nullptr;
+
+  // Match true value as icmp slt X, 0
+  Value *X;
+  if (!match(TrueVal, m_SpecificICmp(ICmpInst::ICMP_SLT, m_Value(X), m_Zero())))
+    return nullptr;
+
+  // Match condition as xor (trunc (lshr/ashr X, N-1)), 1
+  Value *ShiftAmt;
+  bool Matched = match(CondVal, m_Xor(m_Trunc(m_LShr(m_Specific(X), m_Value(ShiftAmt))),
+                                      m_One()));
+  if (!Matched)
+    Matched = match(CondVal, m_Xor(m_Trunc(m_AShr(m_Specific(X), m_Value(ShiftAmt))),
+                                   m_One()));
+  if (!Matched)
+    return nullptr;
+
+  // Check that the shift amount is N-1 (sign bit position)
+  Type *XTy = X->getType();
+  if (!XTy->isIntOrIntVectorTy())
+    return nullptr;
+  unsigned BitWidth = XTy->getScalarSizeInBits();
+  if (!match(ShiftAmt, m_SpecificInt(APInt(BitWidth, BitWidth - 1))))
+    return nullptr;

+  // All patterns matched, the select always evaluates to false
+  return ConstantInt::getFalse(SI.getType());
+}
 static Value *foldSelectBitTest(SelectInst &Sel, Value *CondVal, Value *TrueVal,
                                 Value *FalseVal,
                                 InstCombiner::BuilderTy &Builder,
                                 const SimplifyQuery &SQ) {
   // If this is a vector select, we need a vector compare.
-  Type *SelType = Sel.getType();
-  if (SelType->isVectorTy() != CondVal->getType()->isVectorTy())
-    return nullptr;
-
   Value *V;
   APInt AndMask;
   bool CreateAnd = false;
@@ -4095,6 +4125,9 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
     if (Instruction *Result = foldSelectInstWithICmp(SI, ICI))
       return Result;

+  if (Value *V = foldSelectInvertedSignBitWithSlt(SI, CondVal, TrueVal, FalseVal))
+    return replaceInstUsesWith(SI, V);
+
   if (Value *V = foldSelectBitTest(SI, CondVal, TrueVal, FalseVal, Builder, SQ))
     return replaceInstUsesWith(SI, V);

